 1→import React from 'react';
 2→import { Loader2 } from 'lucide-react';
 3→
 4→type ButtonVariant = 'primary' | 'secondary' | 'ghost' | 'danger';
 5→type ButtonSize = 'sm' | 'md' | 'lg';
 6→
 7→interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
 8→  variant?: ButtonVariant;
 9→  size?: ButtonSize;
10→  icon?: React.ReactNode;
11→  iconPosition?: 'left' | 'right';
12→  loading?: boolean;
13→  children?: React.ReactNode;
14→}
15→
16→const variantClasses: Record<ButtonVariant, string> = {
17→  primary:
18→    'bg-[var(--accent)] text-white hover:opacity-90 active:opacity-80',
19→  secondary:
20→    'border border-[var(--border-default)] text-[var(--text-primary)] bg-[var(--bg-surface)] hover:bg-[var(--bg-elevated)]',
21→  ghost:
22→    'text-[var(--text-secondary)] hover:bg-[var(--bg-elevated)] hover:text-[var(--text-primary)]',
23→  danger:
24→    'bg-red-600 text-white hover:bg-red-700 active:bg-red-800',
25→};
26→
27→const sizeClasses: Record<ButtonSize, string> = {
28→  sm: 'px-3 py-1.5 text-sm gap-1.5',
29→  md: 'px-4 py-2 text-sm gap-2',
30→  lg: 'px-6 py-3 text-base gap-2.5',
31→};
32→
33→export function Button({
34→  variant = 'primary',
35→  size = 'md',
36→  icon,
37→  iconPosition = 'left',
38→  loading = false,
39→  disabled,
40→  children,
41→  className = '',
42→  ...props
43→}: ButtonProps) {
44→  const isDisabled = disabled || loading;
45→
46→  return (
47→    <button
48→      className={`
49→        inline-flex items-center justify-center font-medium rounded-lg
50→        transition-all duration-150 cursor-pointer
51→        disabled:opacity-50 disabled:cursor-not-allowed
52→        ${variantClasses[variant]}
53→        ${sizeClasses[size]}
54→        ${className}
55→      `.trim()}
56→      disabled={isDisabled}
57→      {...props}
58→    >
59→      {loading && (
60→        <Loader2 className="w-4 h-4 animate-spin shrink-0" />
61→      )}
62→      {!loading && icon && iconPosition === 'left' && (
63→        <span className="shrink-0">{icon}</span>
64→      )}
65→      {children && <span>{children}</span>}
66→      {!loading && icon && iconPosition === 'right' && (
67→        <span className="shrink-0">{icon}</span>
68→      )}
69→    </button>
70→  );
71→}
72→

 1→import React from 'react';
 2→
 3→type CardPadding = 'none' | 'sm' | 'md' | 'lg';
 4→
 5→interface CardProps {
 6→  children: React.ReactNode;
 7→  hover?: boolean;
 8→  padding?: CardPadding;
 9→  className?: string;
10→  onClick?: () => void;
11→}
12→
13→const paddingClasses: Record<CardPadding, string> = {
14→  none: 'p-0',
15→  sm: 'p-3',
16→  md: 'p-5',
17→  lg: 'p-8',
18→};
19→
20→export function Card({
21→  children,
22→  hover = false,
23→  padding = 'md',
24→  className = '',
25→  onClick,
26→}: CardProps) {
27→  return (
28→    <div
29→      className={`
30→        bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl
31→        ${paddingClasses[padding]}
32→        ${hover ? 'transition-shadow duration-200 hover:shadow-md hover:border-[var(--border-hover)]' : ''}
33→        ${onClick ? 'cursor-pointer' : ''}
34→        ${className}
35→      `.trim()}
36→      onClick={onClick}
37→      role={onClick ? 'button' : undefined}
38→      tabIndex={onClick ? 0 : undefined}
39→      onKeyDown={
40→        onClick
41→          ? (e) => {
42→              if (e.key === 'Enter' || e.key === ' ') {
43→                e.preventDefault();
44→                onClick();
45→              }
46→            }
47→          : undefined
48→      }
49→    >
50→      {children}
51→    </div>
52→  );
53→}
