  1→import React, { useEffect } from 'react';
  2→import { X } from 'lucide-react';
  3→
  4→type ModalSize = 'sm' | 'md' | 'lg';
  5→
  6→interface ModalProps {
  7→  isOpen: boolean;
  8→  onClose: () => void;
  9→  title?: string;
 10→  children: React.ReactNode;
 11→  size?: ModalSize;
 12→}
 13→
 14→const sizeClasses: Record<ModalSize, string> = {
 15→  sm: 'max-w-sm',
 16→  md: 'max-w-lg',
 17→  lg: 'max-w-2xl',
 18→};
 19→
 20→export function Modal({
 21→  isOpen,
 22→  onClose,
 23→  title,
 24→  children,
 25→  size = 'md',
 26→}: ModalProps) {
 27→  useEffect(() => {
 28→    if (!isOpen) return;
 29→
 30→    const handleEscape = (e: KeyboardEvent) => {
 31→      if (e.key === 'Escape') onClose();
 32→    };
 33→
 34→    document.addEventListener('keydown', handleEscape);
 35→    document.body.style.overflow = 'hidden';
 36→
 37→    return () => {
 38→      document.removeEventListener('keydown', handleEscape);
 39→      document.body.style.overflow = '';
 40→    };
 41→  }, [isOpen, onClose]);
 42→
 43→  if (!isOpen) return null;
 44→
 45→  return (
 46→    <div className="fixed inset-0 z-50 flex items-center justify-center">
 47→      {/* Backdrop */}
 48→      <div
 49→        className="absolute inset-0 bg-black/50 backdrop-blur-sm"
 50→        onClick={onClose}
 51→        aria-hidden="true"
 52→      />
 53→
 54→      {/* Content */}
 55→      <div
 56→        className={`
 57→          relative w-full ${sizeClasses[size]} mx-4
 58→          bg-[var(--bg-surface)] border border-[var(--border-default)]
 59→          rounded-xl shadow-xl
 60→          animate-in fade-in zoom-in-95 duration-200
 61→        `.trim()}
 62→        role="dialog"
 63→        aria-modal="true"
 64→        aria-label={title}
 65→      >
 66→        {/* Header */}
 67→        {title && (
 68→          <div className="flex items-center justify-between px-6 py-4 border-b border-[var(--border-default)]">
 69→            <h2 className="text-lg font-semibold text-[var(--text-primary)]">
 70→              {title}
 71→            </h2>
 72→            <button
 73→              onClick={onClose}
 74→              className="
 75→                p-1.5 rounded-lg transition-colors
 76→                text-[var(--text-secondary)] hover:text-[var(--text-primary)]
 77→                hover:bg-[var(--bg-elevated)]
 78→              "
 79→              aria-label="Close modal"
 80→            >
 81→              <X className="w-5 h-5" />
 82→            </button>
 83→          </div>
 84→        )}
 85→
 86→        {/* Close button when no title */}
 87→        {!title && (
 88→          <button
 89→            onClick={onClose}
 90→            className="
 91→              absolute top-3 right-3 p-1.5 rounded-lg transition-colors
 92→              text-[var(--text-secondary)] hover:text-[var(--text-primary)]
 93→              hover:bg-[var(--bg-elevated)]
 94→            "
 95→            aria-label="Close modal"
 96→          >
 97→            <X className="w-5 h-5" />
 98→          </button>
 99→        )}
100→
101→        {/* Body */}
102→        <div className="px-6 py-4">{children}</div>
103→      </div>
104→    </div>
105→  );
106→}
107→

 1→import React from 'react';
 2→
 3→interface ToggleProps {
 4→  enabled: boolean;
 5→  onChange: (enabled: boolean) => void;
 6→  label?: string;
 7→  className?: string;
 8→}
 9→
10→export function Toggle({
11→  enabled,
12→  onChange,
13→  label,
14→  className = '',
15→}: ToggleProps) {
16→  return (
17→    <label
