import React, { useState } from 'react';
import {
  Calendar,
  Clock,
  CheckCircle,
  XCircle,
  AlertCircle,
  DollarSign,
  User,
  Mail,
  FileText,
  Link2,
} from 'lucide-react';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { StatsCard } from '../components/ui/StatsCard';
import { Toggle } from '../components/ui/Toggle';
import { Button } from '../components/ui/Button';
import { demoBookingConfig, demoBookings, demoProducts } from '../lib/demo-data';
import type { Booking, BookingConfig } from '../types';

const statusBadgeVariant: Record<Booking['status'], 'accent' | 'success' | 'warning' | 'error'> = {
  confirmed: 'accent',
  completed: 'success',
  pending: 'warning',
  cancelled: 'error',
};

const statusIcon: Record<Booking['status'], React.ReactNode> = {
  confirmed: <CheckCircle className="w-3.5 h-3.5" />,
  completed: <CheckCircle className="w-3.5 h-3.5" />,
  pending: <AlertCircle className="w-3.5 h-3.5" />,
  cancelled: <XCircle className="w-3.5 h-3.5" />,
};

function formatDate(dateStr: string): string {
  const date = new Date(dateStr + 'T00:00:00');
  return date.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

function formatTime(time: string): string {
  const [h, m] = time.split(':').map(Number);
  const ampm = h >= 12 ? 'PM' : 'AM';
  const hour12 = h % 12 || 12;
  return `${hour12}:${m.toString().padStart(2, '0')} ${ampm}`;
}

const DAY_ORDER = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];

export default function Bookings() {
  const [config, setConfig] = useState<BookingConfig>(demoBookingConfig);
  const bookingProduct = demoProducts.find((p) => p.id === demoBookingConfig.productId);

  const upcomingCount = demoBookings.filter((b) => b.status === 'confirmed').length;
  const completedCount = demoBookings.filter((b) => b.status === 'completed').length;
  const totalRevenue = bookingProduct
    ? demoBookings.filter((b) => b.status === 'completed' || b.status === 'confirmed').length *
      bookingProduct.price
    : 0;

  const handleAvailabilityToggle = (day: string, enabled: boolean) => {
    setConfig((prev) => ({
      ...prev,
      availability: {
        ...prev.availability,
        [day]: { ...prev.availability[day], enabled },
      },
    }));
  };

  const handleTimeChange = (day: string, field: 'start' | 'end', value: string) => {
    setConfig((prev) => ({
      ...prev,
      availability: {
        ...prev.availability,
        [day]: { ...prev.availability[day], [field]: value },
      },
    }));
  };

  return (
    <div className="page-enter space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Bookings</h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            Manage your 1-on-1 sessions and availability
          </p>
        </div>
        <Button icon={<Calendar className="w-4 h-4" />}>New Booking</Button>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <StatsCard
          label="Upcoming Bookings"
          value={upcomingCount}
          icon={<Calendar className="w-5 h-5" />}
          change={12}
          changeLabel="vs last month"
        />
        <StatsCard
          label="Completed"
          value={completedCount}
          icon={<CheckCircle className="w-5 h-5" />}
          change={8}
          changeLabel="vs last month"
        />
        <StatsCard
          label="Total Revenue"
          value={`$${totalRevenue.toLocaleString()}`}
          icon={<DollarSign className="w-5 h-5" />}
          change={15}
          changeLabel="vs last month"
        />
      </div>

      {/* Configuration Panel */}
      <Card>
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-[var(--text-primary)]">
            Booking Configuration
          </h2>
          <Button variant="secondary" size="sm">
            Save Changes
          </Button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {/* Duration */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-[var(--text-secondary)]">
              Session Duration
            </label>
            <div className="flex items-center gap-2">
              <Clock className="w-4 h-4 text-[var(--text-tertiary)]" />
              <span className="text-base font-semibold text-[var(--text-primary)]">
                {config.duration} minutes
              </span>
            </div>
          </div>

          {/* Buffer Times */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-[var(--text-secondary)]">Buffer Times</label>
            <div className="text-sm text-[var(--text-primary)]">
              <span>{config.bufferBefore} min before</span>
              <span className="mx-2 text-[var(--text-tertiary)]">/</span>
              <span>{config.bufferAfter} min after</span>
            </div>
          </div>

          {/* Calendar Connection */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-[var(--text-secondary)]">
              Calendar Connection
            </label>
            <div className="flex items-center gap-2">
              <Badge variant={config.calendarConnected ? 'success' : 'warning'}>
                <span className="flex items-center gap-1.5">
                  <Link2 className="w-3 h-3" />
                  {config.calendarConnected ? 'Connected' : 'Not Connected'}
                </span>
              </Badge>
            </div>
          </div>
        </div>
      </Card>

      {/* Weekly Availability Grid */}
      <Card>
        <h2 className="text-lg font-semibold text-[var(--text-primary)] mb-4">
          Weekly Availability
        </h2>
        <div className="space-y-3">
          {DAY_ORDER.map((day) => {
            const slot = config.availability[day];
            if (!slot) return null;
            return (
              <div
                key={day}
                className={`flex items-center gap-4 p-3 rounded-lg transition-colors ${
                  slot.enabled
                    ? 'bg-[var(--bg-base)]'
                    : 'bg-[var(--bg-elevated)] opacity-60'
                }`}
              >
                <div className="w-28 shrink-0">
                  <span className="text-sm font-medium text-[var(--text-primary)] capitalize">
                    {day}
                  </span>
                </div>

                <Toggle
                  enabled={slot.enabled}
                  onChange={(enabled) => handleAvailabilityToggle(day, enabled)}
                />

                <div className="flex items-center gap-2 flex-1">
                  <input
                    type="time"
                    value={slot.start}
                    disabled={!slot.enabled}
                    onChange={(e) => handleTimeChange(day, 'start', e.target.value)}
                    className="px-3 py-1.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] disabled:opacity-40 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
                  />
                  <span className="text-sm text-[var(--text-tertiary)]">to</span>
                  <input
                    type="time"
                    value={slot.end}
                    disabled={!slot.enabled}
                    onChange={(e) => handleTimeChange(day, 'end', e.target.value)}
                    className="px-3 py-1.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] disabled:opacity-40 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
                  />
                </div>

                {slot.enabled && (
                  <span className="text-xs text-[var(--text-tertiary)] shrink-0">
                    {formatTime(slot.start)} - {formatTime(slot.end)}
                  </span>
                )}
              </div>
            );
          })}
        </div>
      </Card>

      {/* Upcoming Bookings List */}
      <div>
        <h2 className="text-lg font-semibold text-[var(--text-primary)] mb-4">
          Upcoming Bookings
        </h2>
        <div className="space-y-4">
          {demoBookings.map((booking) => (
            <Card key={booking.id} hover>
              <div className="flex items-start justify-between">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="text-base font-semibold text-[var(--text-primary)]">
                      {booking.customerName}
                    </h3>
                    <Badge variant={statusBadgeVariant[booking.status]}>
                      <span className="flex items-center gap-1">
                        {statusIcon[booking.status]}
                        {booking.status.charAt(0).toUpperCase() + booking.status.slice(1)}
                      </span>
                    </Badge>
                  </div>

                  <div className="flex flex-wrap items-center gap-4 text-sm text-[var(--text-secondary)]">
                    <span className="flex items-center gap-1.5">
                      <Mail className="w-3.5 h-3.5" />
                      {booking.customerEmail}
                    </span>
                    <span className="flex items-center gap-1.5">
                      <Calendar className="w-3.5 h-3.5" />
                      {formatDate(booking.date)}
                    </span>
                    <span className="flex items-center gap-1.5">
                      <Clock className="w-3.5 h-3.5" />
                      {formatTime(booking.time)}
                    </span>
                  </div>

                  {booking.notes && (
                    <div className="mt-3 flex items-start gap-1.5 text-sm text-[var(--text-secondary)]">
                      <FileText className="w-3.5 h-3.5 mt-0.5 shrink-0" />
                      <span>{booking.notes}</span>
                    </div>
                  )}
                </div>

                <div className="flex items-center gap-2 shrink-0 ml-4">
                  {booking.status === 'confirmed' && (
                    <>
                      <Button variant="ghost" size="sm">
                        Reschedule
                      </Button>
                      <Button variant="danger" size="sm">
                        Cancel
                      </Button>
                    </>
                  )}
                  {booking.status === 'completed' && (
                    <Button variant="secondary" size="sm">
                      View Details
                    </Button>
                  )}
                </div>
              </div>
            </Card>
          ))}
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import {
  Users,
  DollarSign,
  CheckCircle,
  Plus,
  Download,
  UserPlus,
  TrendingUp,
  Edit3,
  Crown,
  BarChart3,
} from 'lucide-react';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { StatsCard } from '../components/ui/StatsCard';
import { DataTable } from '../components/ui/DataTable';
import { Button } from '../components/ui/Button';
import { demoMembership, demoProducts, demoSubscribers } from '../lib/demo-data';
import type { Membership, Subscriber } from '../types';

// Use subscribers as mock members
const mockMembers = demoSubscribers.map((sub, i) => ({
  ...sub,
  joinedAt: sub.subscribedAt,
  status: i < 4 ? ('active' as const) : ('churned' as const),
}));

type MemberRow = (typeof mockMembers)[number] & Record<string, unknown>;

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

// Mock growth data for the chart
const growthData = [
  { month: 'Sep', members: 42 },
  { month: 'Oct', members: 61 },
  { month: 'Nov', members: 78 },
  { month: 'Dec', members: 95 },
  { month: 'Jan', members: 112 },
  { month: 'Feb', members: 128 },
];

const maxMembers = Math.max(...growthData.map((d) => d.members));

export default function Memberships() {
  const [editingBenefits, setEditingBenefits] = useState(false);
  const membershipProduct = demoProducts.find((p) => p.id === demoMembership.productId);

  const monthlyPrice = membershipProduct?.price ?? 39;
  const memberCount = demoMembership.memberCount;
  const mrr = memberCount * monthlyPrice;

  const memberColumns = [
    {
      key: 'name',
      label: 'Name',
      render: (_: unknown, row: MemberRow) => (
        <span className="font-medium text-[var(--text-primary)]">{row.name}</span>
      ),
    },
    {
      key: 'email',
      label: 'Email',
      render: (_: unknown, row: MemberRow) => (
        <span className="text-[var(--text-secondary)]">{row.email}</span>
      ),
    },
    {
      key: 'joinedAt',
      label: 'Joined',
      render: (_: unknown, row: MemberRow) => (
        <span className="text-[var(--text-secondary)]">{formatDate(row.joinedAt)}</span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      render: (_: unknown, row: MemberRow) => (
        <Badge variant={row.status === 'active' ? 'success' : 'error'}>
          {row.status.charAt(0).toUpperCase() + row.status.slice(1)}
        </Badge>
      ),
    },
  ];

  return (
    <div className="page-enter space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Memberships</h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            Manage your membership program and members
          </p>
        </div>
        <div className="flex items-center gap-3">
          <Button variant="secondary" icon={<Download className="w-4 h-4" />}>
            Export Members
          </Button>
          <Button icon={<UserPlus className="w-4 h-4" />}>Invite Member</Button>
        </div>
      </div>

      {/* Overview Card */}
      <Card>
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-[var(--accent)]/10 flex items-center justify-center">
              <Crown className="w-5 h-5 text-[var(--accent)]" />
            </div>
            <div>
              <h2 className="text-lg font-semibold text-[var(--text-primary)]">
                {membershipProduct?.title ?? 'Creator Inner Circle'}
              </h2>
              <p className="text-sm text-[var(--text-secondary)]">Membership program overview</p>
            </div>
          </div>
          <Badge variant="accent">{demoMembership.interval}</Badge>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
          <div>
            <p className="text-sm text-[var(--text-secondary)] mb-1">Members</p>
            <p className="text-2xl font-bold text-[var(--text-primary)]">{memberCount}</p>
          </div>
          <div>
            <p className="text-sm text-[var(--text-secondary)] mb-1">Monthly Price</p>
            <p className="text-2xl font-bold text-[var(--text-primary)]">${monthlyPrice}</p>
          </div>
          <div>
            <p className="text-sm text-[var(--text-secondary)] mb-1">MRR</p>
            <p className="text-2xl font-bold text-[var(--text-primary)]">
              ${mrr.toLocaleString()}
            </p>
          </div>
          <div>
            <p className="text-sm text-[var(--text-secondary)] mb-1">Interval</p>
