import React, { useState, useMemo } from 'react';
import {
  ShoppingCart,
  DollarSign,
  RotateCcw,
  TrendingUp,
  Search,
  Download,
  CreditCard,
  Wallet,
  ChevronDown,
  ChevronUp,
  Package,
} from 'lucide-react';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { StatsCard } from '../components/ui/StatsCard';
import { DataTable } from '../components/ui/DataTable';
import { Tabs } from '../components/ui/Tabs';
import { Button } from '../components/ui/Button';
import { demoOrders } from '../lib/demo-data';
import type { Order } from '../types';

type OrderRow = Order & Record<string, unknown>;

const statusBadgeVariant: Record<Order['status'], 'success' | 'warning' | 'error' | 'default'> = {
  completed: 'success',
  pending: 'warning',
  refunded: 'error',
  failed: 'error',
};

const filterTabs = [
  { id: 'all', label: 'All' },
  { id: 'completed', label: 'Completed' },
  { id: 'pending', label: 'Pending' },
  { id: 'refunded', label: 'Refunded' },
];

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
}

function formatAmount(amount: number, currency: string): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency,
    minimumFractionDigits: 2,
  }).format(amount);
}

export default function Orders() {
  const [activeTab, setActiveTab] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [expandedOrderId, setExpandedOrderId] = useState<string | null>(null);

  // Stats calculations
  const totalOrders = demoOrders.length;
  const totalRevenue = demoOrders
    .filter((o) => o.status === 'completed')
    .reduce((sum, o) => sum + o.amount, 0);
  const refundedCount = demoOrders.filter((o) => o.status === 'refunded').length;
  const refundRate = totalOrders > 0 ? ((refundedCount / totalOrders) * 100).toFixed(1) : '0.0';
  const completedOrders = demoOrders.filter((o) => o.status === 'completed');
  const avgOrderValue =
    completedOrders.length > 0
      ? (completedOrders.reduce((sum, o) => sum + o.amount, 0) / completedOrders.length).toFixed(2)
      : '0.00';

  // Filter and search
  const filteredOrders = useMemo(() => {
    let orders = demoOrders;

    if (activeTab !== 'all') {
      orders = orders.filter((o) => o.status === activeTab);
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      orders = orders.filter(
        (o) =>
          o.customerName.toLowerCase().includes(q) ||
          o.customerEmail.toLowerCase().includes(q) ||
          o.productTitle.toLowerCase().includes(q) ||
          o.id.toLowerCase().includes(q)
      );
    }

    return orders;
  }, [activeTab, searchQuery]);

  const columns = [
    {
      key: 'id',
      label: 'Order ID',
      render: (_: unknown, row: OrderRow) => (
        <span className="font-mono text-xs text-[var(--accent)]">{row.id}</span>
      ),
    },
    {
      key: 'customerName',
      label: 'Customer',
      render: (_: unknown, row: OrderRow) => (
        <div>
          <p className="font-medium text-[var(--text-primary)]">{row.customerName}</p>
          <p className="text-xs text-[var(--text-tertiary)]">{row.customerEmail}</p>
        </div>
      ),
    },
    {
      key: 'productTitle',
      label: 'Product',
      render: (_: unknown, row: OrderRow) => (
        <span className="text-[var(--text-primary)]">{row.productTitle}</span>
      ),
    },
    {
      key: 'amount',
      label: 'Amount',
      render: (_: unknown, row: OrderRow) => (
        <span className="font-semibold text-[var(--text-primary)]">
          {formatAmount(row.amount, row.currency)}
        </span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      render: (_: unknown, row: OrderRow) => (
        <Badge variant={statusBadgeVariant[row.status]}>
          {row.status.charAt(0).toUpperCase() + row.status.slice(1)}
        </Badge>
      ),
    },
    {
      key: 'paymentMethod',
      label: 'Payment',
      render: (_: unknown, row: OrderRow) => (
        <span className="flex items-center gap-1.5 text-[var(--text-secondary)]">
          {row.paymentMethod === 'stripe' ? (
            <CreditCard className="w-3.5 h-3.5" />
          ) : (
            <Wallet className="w-3.5 h-3.5" />
          )}
          <span className="text-xs capitalize">{row.paymentMethod}</span>
        </span>
      ),
    },
    {
      key: 'createdAt',
      label: 'Date',
      render: (_: unknown, row: OrderRow) => (
        <span className="text-sm text-[var(--text-secondary)]">{formatDate(row.createdAt)}</span>
      ),
    },
  ];

  return (
    <div className="page-enter space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Orders</h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            Track and manage all your transactions
          </p>
        </div>
        <Button variant="secondary" icon={<Download className="w-4 h-4" />}>
          Export CSV
        </Button>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatsCard
          label="Total Orders"
          value={totalOrders}
          icon={<ShoppingCart className="w-5 h-5" />}
          change={18}
          changeLabel="vs last month"
        />
        <StatsCard
          label="Revenue"
          value={`$${totalRevenue.toLocaleString()}`}
          icon={<DollarSign className="w-5 h-5" />}
          change={12}
          changeLabel="vs last month"
        />
        <StatsCard
          label="Refund Rate"
          value={`${refundRate}%`}
          icon={<RotateCcw className="w-5 h-5" />}
          change={-2.1}
          changeLabel="vs last month"
        />
        <StatsCard
          label="Avg Order Value"
          value={`$${avgOrderValue}`}
          icon={<TrendingUp className="w-5 h-5" />}
          change={5.3}
          changeLabel="vs last month"
        />
      </div>

      {/* Filter + Search */}
      <div className="space-y-4">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <Tabs tabs={filterTabs} activeTab={activeTab} onChange={setActiveTab} />

          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-tertiary)]" />
            <input
              type="text"
              placeholder="Search orders..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9 pr-4 py-2 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] w-full sm:w-64"
            />
          </div>
        </div>

        {/* Orders Table */}
        <DataTable
          columns={columns}
          data={filteredOrders as unknown as OrderRow[]}
          onRowClick={(row) => {
            setExpandedOrderId(expandedOrderId === row.id ? null : row.id);
          }}
        />

        {/* Expanded Order Detail (conceptual) */}
        {expandedOrderId && (
          <Card className="border-l-4 border-l-[var(--accent)]">
            {(() => {
              const order = demoOrders.find((o) => o.id === expandedOrderId);
              if (!order) return null;
              return (
                <div className="space-y-3">
                  <div className="flex items-center justify-between">
                    <h3 className="text-base font-semibold text-[var(--text-primary)]">
                      Order Details: {order.id}
                    </h3>
                    <button
                      onClick={() => setExpandedOrderId(null)}
                      className="text-[var(--text-tertiary)] hover:text-[var(--text-primary)] transition-colors"
                    >
                      <ChevronUp className="w-4 h-4" />
                    </button>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                    <div>
                      <p className="text-[var(--text-secondary)]">Customer</p>
                      <p className="font-medium text-[var(--text-primary)]">
                        {order.customerName}
                      </p>
                      <p className="text-xs text-[var(--text-tertiary)]">{order.customerEmail}</p>
                    </div>
                    <div>
                      <p className="text-[var(--text-secondary)]">Product</p>
                      <p className="font-medium text-[var(--text-primary)]">
                        {order.productTitle}
                      </p>
                    </div>
                    <div>
                      <p className="text-[var(--text-secondary)]">Amount</p>
                      <p className="font-medium text-[var(--text-primary)]">
                        {formatAmount(order.amount, order.currency)}
                      </p>
                    </div>
                    <div>
                      <p className="text-[var(--text-secondary)]">Date</p>
                      <p className="font-medium text-[var(--text-primary)]">
                        {formatDate(order.createdAt)}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-2 pt-2">
                    <Badge variant={statusBadgeVariant[order.status]}>
                      {order.status.charAt(0).toUpperCase() + order.status.slice(1)}
                    </Badge>
                    <span className="flex items-center gap-1 text-xs text-[var(--text-secondary)]">
                      {order.paymentMethod === 'stripe' ? (
                        <CreditCard className="w-3 h-3" />
                      ) : (
                        <Wallet className="w-3 h-3" />
                      )}
                      Paid via {order.paymentMethod}
                    </span>
                  </div>

                  {order.status === 'completed' && (
                    <div className="flex items-center gap-2 pt-2">
                      <Button variant="secondary" size="sm">
                        Send Receipt
                      </Button>
                      <Button variant="ghost" size="sm">
                        Issue Refund
                      </Button>
                    </div>
                  )}
                </div>
              );
            })()}
          </Card>
        )}

        {/* Results count */}
        <p className="text-xs text-[var(--text-tertiary)]">
          Showing {filteredOrders.length} of {demoOrders.length} orders
        </p>
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Users,
  UserPlus,
  Download,
  Upload,
  Search,
  Tag,
  ShoppingCart,
  Gift,
  ChevronDown,
  X,
  Trash2,
  Plus,
  Minus,
} from 'lucide-react';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { StatsCard } from '../components/ui/StatsCard';
import { DataTable } from '../components/ui/DataTable';
import { Button } from '../components/ui/Button';
import { demoSubscribers } from '../lib/demo-data';
import type { Subscriber } from '../types';

type SubscriberRow = Subscriber & Record<string, unknown>;

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

// Extract all unique tags from subscribers
function getAllTags(subscribers: Subscriber[]): string[] {
  const tags = new Set<string>();
  subscribers.forEach((sub) => sub.tags.forEach((tag) => tags.add(tag)));
  return Array.from(tags).sort();
}

// Source display names
const sourceLabels: Record<string, string> = {
  purchase: 'Purchase',
  'free-download': 'Free Download',
  'webinar-signup': 'Webinar Signup',
  manual: 'Manual',
};

export default function Subscribers() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [showBulkActions, setShowBulkActions] = useState(false);
  const [selectedRows, setSelectedRows] = useState<Set<string>>(new Set());

  const allTags = useMemo(() => getAllTags(demoSubscribers), []);

  // Stats
  const totalSubscribers = demoSubscribers.length;
  const newThisMonth = demoSubscribers.filter((s) => {
    const subDate = new Date(s.subscribedAt);
    const now = new Date();
    return subDate.getMonth() === now.getMonth() && subDate.getFullYear() === now.getFullYear();
  }).length;
  const fromPurchases = demoSubscribers.filter((s) => s.source === 'purchase').length;
  const fromFreeDownloads = demoSubscribers.filter((s) => s.source === 'free-download').length;

  // Filter and search
  const filteredSubscribers = useMemo(() => {
    let subs = demoSubscribers;

    if (selectedTag) {
      subs = subs.filter((s) => s.tags.includes(selectedTag));
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      subs = subs.filter(
        (s) =>
          s.name.toLowerCase().includes(q) ||
          s.email.toLowerCase().includes(q) ||
          s.tags.some((t) => t.toLowerCase().includes(q))
      );
    }

    return subs;
  }, [selectedTag, searchQuery]);

  const toggleRowSelection = (id: string) => {
    setSelectedRows((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const toggleSelectAll = () => {
    if (selectedRows.size === filteredSubscribers.length) {
      setSelectedRows(new Set());
    } else {
      setSelectedRows(new Set(filteredSubscribers.map((s) => s.id)));
    }
  };

  const columns = [
    {
      key: 'select',
      label: '',
      render: (_: unknown, row: SubscriberRow) => (
        <input
          type="checkbox"
          checked={selectedRows.has(row.id)}
          onChange={() => toggleRowSelection(row.id)}
          onClick={(e) => e.stopPropagation()}
          className="w-4 h-4 rounded border-[var(--border-default)] text-[var(--accent)] focus:ring-[var(--accent)] cursor-pointer"
        />
      ),
    },
    {
      key: 'name',
      label: 'Name',
      render: (_: unknown, row: SubscriberRow) => (
        <span className="font-medium text-[var(--text-primary)]">{row.name}</span>
      ),
    },
    {
      key: 'email',
      label: 'Email',
      render: (_: unknown, row: SubscriberRow) => (
        <span className="text-[var(--text-secondary)]">{row.email}</span>
      ),
    },
    {
      key: 'tags',
      label: 'Tags',
      render: (_: unknown, row: SubscriberRow) => (
        <div className="flex flex-wrap gap-1">
          {row.tags.map((tag: string) => (
            <Badge key={tag} variant="accent">
              {tag}
            </Badge>
          ))}
        </div>
      ),
    },
    {
      key: 'source',
      label: 'Source',
      render: (_: unknown, row: SubscriberRow) => (
        <span className="text-sm text-[var(--text-secondary)]">
          {sourceLabels[row.source] || row.source}
        </span>
      ),
    },
    {
      key: 'subscribedAt',
      label: 'Subscribed',
      render: (_: unknown, row: SubscriberRow) => (
        <span className="text-sm text-[var(--text-secondary)]">{formatDate(row.subscribedAt)}</span>
      ),
    },
  ];

  return (
    <div className="page-enter space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Subscribers</h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            Manage your email subscriber list
          </p>
        </div>
        <div className="flex items-center gap-3">
          <Button variant="secondary" icon={<Upload className="w-4 h-4" />}>
            Import Subscribers
          </Button>
          <Button variant="secondary" icon={<Download className="w-4 h-4" />}>
            Export List
          </Button>
        </div>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatsCard
          label="Total Subscribers"
          value={totalSubscribers}
          icon={<Users className="w-5 h-5" />}
          change={24}
          changeLabel="vs last month"
        />
        <StatsCard
          label="New This Month"
          value={newThisMonth}
          icon={<UserPlus className="w-5 h-5" />}
          change={8}
          changeLabel="vs last month"
        />
        <StatsCard
          label="From Purchases"
          value={fromPurchases}
          icon={<ShoppingCart className="w-5 h-5" />}
        />
        <StatsCard
          label="From Free Downloads"
          value={fromFreeDownloads}
          icon={<Gift className="w-5 h-5" />}
        />
      </div>

      {/* Tag Filters */}
      <Card>
        <div className="flex items-center justify-between mb-3">
          <h3 className="text-sm font-medium text-[var(--text-secondary)]">Filter by Tag</h3>
          {selectedTag && (
            <button
              onClick={() => setSelectedTag(null)}
              className="text-xs text-[var(--accent)] hover:underline"
            >
              Clear filter
            </button>
          )}
        </div>
        <div className="flex flex-wrap gap-2">
          {allTags.map((tag) => (
            <button
              key={tag}
              onClick={() => setSelectedTag(selectedTag === tag ? null : tag)}
              className={`
                inline-flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-full
                transition-all duration-150 cursor-pointer
                ${
                  selectedTag === tag
                    ? 'bg-[var(--accent)] text-white'
                    : 'bg-[var(--bg-elevated)] text-[var(--text-secondary)] border border-[var(--border-default)] hover:border-[var(--accent)] hover:text-[var(--accent)]'
                }
              `}
            >
              <Tag className="w-3 h-3" />
              {tag}
            </button>
          ))}
        </div>
      </Card>

      {/* Search + Bulk Actions */}
      <div className="flex flex-col sm:flex-row sm:items-center gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-tertiary)]" />
          <input
            type="text"
            placeholder="Search by name, email, or tag..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-2 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
          />
        </div>

        {selectedRows.size > 0 && (
          <div className="relative">
            <Button
              variant="secondary"
              size="sm"
              icon={<ChevronDown className="w-3.5 h-3.5" />}
              iconPosition="right"
              onClick={() => setShowBulkActions(!showBulkActions)}
            >
              Bulk Actions ({selectedRows.size})
            </Button>

            {showBulkActions && (
              <div className="absolute right-0 top-full mt-1 w-48 bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-lg shadow-lg z-10 py-1">
                <button className="w-full flex items-center gap-2 px-3 py-2 text-sm text-[var(--text-primary)] hover:bg-[var(--bg-elevated)] transition-colors">
                  <Plus className="w-3.5 h-3.5" />
                  Add Tag
                </button>
                <button className="w-full flex items-center gap-2 px-3 py-2 text-sm text-[var(--text-primary)] hover:bg-[var(--bg-elevated)] transition-colors">
                  <Minus className="w-3.5 h-3.5" />
                  Remove Tag
                </button>
                <div className="border-t border-[var(--border-default)] my-1" />
                <button className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 transition-colors">
                  <Trash2 className="w-3.5 h-3.5" />
                  Delete
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Subscribers Table */}
      <div>
        <div className="flex items-center gap-3 mb-3">
          <input
            type="checkbox"
            checked={
              selectedRows.size === filteredSubscribers.length && filteredSubscribers.length > 0
            }
            onChange={toggleSelectAll}
            className="w-4 h-4 rounded border-[var(--border-default)] text-[var(--accent)] focus:ring-[var(--accent)] cursor-pointer"
          />
          <span className="text-xs text-[var(--text-tertiary)]">
            {selectedRows.size > 0
              ? `${selectedRows.size} selected`
              : `${filteredSubscribers.length} subscribers`}
          </span>
        </div>

        <DataTable
          columns={columns}
          data={filteredSubscribers as unknown as SubscriberRow[]}
        />

        <p className="text-xs text-[var(--text-tertiary)] mt-3">
          Showing {filteredSubscribers.length} of {demoSubscribers.length} subscribers
          {selectedTag && (
            <span>
              {' '}filtered by tag{' '}
              <Badge variant="accent" className="ml-1">
                {selectedTag}
              </Badge>
            </span>
          )}
        </p>
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Users,
  UserCheck,
  DollarSign,
  Banknote,
  Plus,
  Copy,
  Check,
  Link2,
  Settings,
  Clock,
  Percent,
  ExternalLink,
} from 'lucide-react';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { StatsCard } from '../components/ui/StatsCard';
import { DataTable } from '../components/ui/DataTable';
import { Button } from '../components/ui/Button';
import { demoAffiliates, demoUser } from '../lib/demo-data';
import type { Affiliate } from '../types';

type AffiliateRow = Affiliate & Record<string, unknown>;

const statusBadgeVariant: Record<Affiliate['status'], 'success' | 'warning' | 'error'> = {
  active: 'success',
  pending: 'warning',
  disabled: 'error',
};

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2,
  }).format(amount);
}

export default function Affiliates() {
  const [showAddForm, setShowAddForm] = useState(false);
  const [copiedCode, setCopiedCode] = useState<string | null>(null);
  const [defaultCommission, setDefaultCommission] = useState(20);
  const [cookieDuration, setCookieDuration] = useState(30);

  // Stats
  const totalAffiliates = demoAffiliates.length;
  const activeAffiliates = demoAffiliates.filter((a) => a.status === 'active').length;
  const totalSales = demoAffiliates.reduce((sum, a) => sum + a.totalSales, 0);
  const totalPayouts = demoAffiliates.reduce((sum, a) => sum + a.totalEarnings, 0);

  const baseUrl = `https://stan.store/${demoUser.username}`;

  const handleCopyLink = (code: string) => {
    const link = `${baseUrl}?ref=${code}`;
    navigator.clipboard.writeText(link).catch(() => {
      // Fallback - not in secure context
    });
    setCopiedCode(code);
    setTimeout(() => setCopiedCode(null), 2000);
  };

  const columns = [
    {
      key: 'name',
      label: 'Name',
      render: (_: unknown, row: AffiliateRow) => (
        <div>
          <p className="font-medium text-[var(--text-primary)]">{row.name}</p>
          <p className="text-xs text-[var(--text-tertiary)]">{row.email}</p>
        </div>
      ),
    },
    {
      key: 'code',
      label: 'Code',
      render: (_: unknown, row: AffiliateRow) => (
        <span className="font-mono text-xs px-2 py-1 rounded bg-[var(--bg-elevated)] text-[var(--accent)]">
          {row.code}
        </span>
      ),
    },
    {
      key: 'commission',
      label: 'Commission',
      render: (_: unknown, row: AffiliateRow) => (
        <span className="text-[var(--text-primary)]">{row.commission}%</span>
      ),
    },
    {
      key: 'totalSales',
      label: 'Sales',
      render: (_: unknown, row: AffiliateRow) => (
        <span className="font-medium text-[var(--text-primary)]">{row.totalSales}</span>
      ),
    },
    {
      key: 'totalEarnings',
      label: 'Earnings',
      render: (_: unknown, row: AffiliateRow) => (
        <span className="font-semibold text-[var(--text-primary)]">
          {formatCurrency(row.totalEarnings)}
        </span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      render: (_: unknown, row: AffiliateRow) => (
        <Badge variant={statusBadgeVariant[row.status]}>
          {row.status.charAt(0).toUpperCase() + row.status.slice(1)}
        </Badge>
      ),
    },
    {
      key: 'actions',
      label: '',
      render: (_: unknown, row: AffiliateRow) => (
        <button
          onClick={(e) => {
            e.stopPropagation();
            handleCopyLink(row.code);
          }}
          className="p-1.5 rounded-lg text-[var(--text-tertiary)] hover:text-[var(--accent)] hover:bg-[var(--bg-elevated)] transition-colors"
          title="Copy affiliate link"
        >
          {copiedCode === row.code ? (
            <Check className="w-4 h-4 text-emerald-500" />
          ) : (
            <Copy className="w-4 h-4" />
          )}
        </button>
      ),
    },
  ];

  return (
    <div className="page-enter space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Affiliates</h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            Manage your affiliate program and track performance
          </p>
        </div>
        <Button
          icon={<Plus className="w-4 h-4" />}
          onClick={() => setShowAddForm(!showAddForm)}
        >
          Add Affiliate
        </Button>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatsCard
          label="Total Affiliates"
          value={totalAffiliates}
          icon={<Users className="w-5 h-5" />}
        />
        <StatsCard
          label="Active"
          value={activeAffiliates}
          icon={<UserCheck className="w-5 h-5" />}
          change={50}
          changeLabel="vs last month"
        />
        <StatsCard
          label="Total Sales via Affiliates"
          value={totalSales}
          icon={<DollarSign className="w-5 h-5" />}
          change={22}
          changeLabel="vs last month"
        />
        <StatsCard
          label="Total Payouts"
          value={formatCurrency(totalPayouts)}
          icon={<Banknote className="w-5 h-5" />}
        />
      </div>

      {/* Add Affiliate Form (conceptual) */}
      {showAddForm && (
        <Card>
          <h2 className="text-lg font-semibold text-[var(--text-primary)] mb-4">
            Add New Affiliate
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-sm font-medium text-[var(--text-secondary)]">Name</label>
              <input
                type="text"
                placeholder="Affiliate name"
                className="w-full px-3 py-2 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-base)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-[var(--text-secondary)]">Email</label>
              <input
                type="email"
                placeholder="affiliate@example.com"
                className="w-full px-3 py-2 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-base)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-[var(--text-secondary)]">
                Affiliate Code
              </label>
              <input
                type="text"
                placeholder="e.g. PARTNER20"
                className="w-full px-3 py-2 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-base)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] uppercase font-mono"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-[var(--text-secondary)]">
                Commission Rate (%)
              </label>
              <input
                type="number"
                defaultValue={defaultCommission}
                min={1}
                max={100}
                className="w-full px-3 py-2 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-base)] text-[var(--text-primary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
              />
            </div>
          </div>
          <div className="flex items-center gap-3 mt-6">
            <Button>Create Affiliate</Button>
            <Button variant="ghost" onClick={() => setShowAddForm(false)}>
              Cancel
            </Button>
          </div>
        </Card>
      )}

      {/* Affiliate Table */}
      <div>
        <h2 className="text-lg font-semibold text-[var(--text-primary)] mb-4">
          Affiliate Partners
        </h2>
        <DataTable
          columns={columns}
          data={demoAffiliates as unknown as AffiliateRow[]}
        />
      </div>

      {/* Affiliate Link Generator */}
      <Card>
        <div className="flex items-center gap-3 mb-4">
          <div className="w-8 h-8 rounded-lg bg-[var(--accent)]/10 flex items-center justify-center">
            <Link2 className="w-4 h-4 text-[var(--accent)]" />
          </div>
          <h2 className="text-lg font-semibold text-[var(--text-primary)]">
            Affiliate Link Generator
          </h2>
        </div>

        <p className="text-sm text-[var(--text-secondary)] mb-4">
          Each affiliate gets a unique referral link based on their code.
        </p>

        <div className="space-y-3">
          {demoAffiliates.map((affiliate) => (
            <div
              key={affiliate.id}
              className="flex items-center gap-3 p-3 rounded-lg bg-[var(--bg-base)] border border-[var(--border-default)]"
            >
              <span className="text-sm font-medium text-[var(--text-primary)] w-32 shrink-0">
                {affiliate.name}
              </span>
              <div className="flex-1 flex items-center gap-2">
                <code className="flex-1 px-3 py-1.5 text-xs font-mono rounded bg-[var(--bg-elevated)] text-[var(--text-secondary)] border border-[var(--border-default)] truncate">
                  {baseUrl}?ref={affiliate.code}
                </code>
                <button
                  onClick={() => handleCopyLink(affiliate.code)}
                  className="p-2 rounded-lg text-[var(--text-tertiary)] hover:text-[var(--accent)] hover:bg-[var(--bg-elevated)] transition-colors shrink-0"
                  title="Copy link"
                >
                  {copiedCode === affiliate.code ? (
                    <Check className="w-4 h-4 text-emerald-500" />
                  ) : (
                    <Copy className="w-4 h-4" />
                  )}
                </button>
              </div>
              <Badge variant={statusBadgeVariant[affiliate.status]} className="shrink-0">
                {affiliate.status}
              </Badge>
            </div>
          ))}
        </div>
      </Card>

      {/* Commission Settings Panel */}
      <Card>
        <div className="flex items-center gap-3 mb-6">
          <div className="w-8 h-8 rounded-lg bg-[var(--bg-elevated)] flex items-center justify-center">
            <Settings className="w-4 h-4 text-[var(--text-secondary)]" />
          </div>
          <h2 className="text-lg font-semibold text-[var(--text-primary)]">
            Commission Settings
          </h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Default Commission */}
          <div className="space-y-3">
            <label className="text-sm font-medium text-[var(--text-secondary)]">
              Default Commission Rate
            </label>
            <div className="flex items-center gap-3">
              <div className="relative flex-1">
                <Percent className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-tertiary)]" />
                <input
                  type="number"
                  value={defaultCommission}
                  onChange={(e) => setDefaultCommission(Number(e.target.value))}
                  min={1}
                  max={100}
                  className="w-full px-3 py-2 pr-9 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-base)] text-[var(--text-primary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
                />
              </div>
            </div>
            <p className="text-xs text-[var(--text-tertiary)]">
              Applied to new affiliates by default. Can be overridden per affiliate.
            </p>
          </div>

          {/* Cookie Duration */}
          <div className="space-y-3">
            <label className="text-sm font-medium text-[var(--text-secondary)]">
              Cookie Duration
            </label>
            <div className="flex items-center gap-3">
              <div className="relative flex-1">
                <Clock className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-tertiary)]" />
                <input
                  type="number"
                  value={cookieDuration}
                  onChange={(e) => setCookieDuration(Number(e.target.value))}
                  min={1}
                  max={365}
                  className="w-full px-3 py-2 pr-9 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-base)] text-[var(--text-primary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)]"
                />
              </div>
              <span className="text-sm text-[var(--text-secondary)]">days</span>
            </div>
            <p className="text-xs text-[var(--text-tertiary)]">
              How long the affiliate tracking cookie lasts after a visitor clicks the referral link.
            </p>
          </div>
        </div>

        <div className="mt-6 pt-4 border-t border-[var(--border-default)]">
          <Button variant="secondary" size="sm">
            Save Settings
          </Button>
        </div>
      </Card>
    </div>
  );
}
